import{_ as e,o as a,c as s,aw as i}from"./chunks/framework.Dq2onT5h.js";const t=JSON.parse('{"title":"Config","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Config | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"learn/config.md","filePath":"learn/config.md","lastUpdated":1775581616000}');const n=e({name:"learn/config.md"},[["render",function(e,t,n,o,l,r){return a(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="config" tabindex="-1">Config <a class="header-anchor" href="#config" aria-label="Permalink to &quot;Config&quot;">​</a></h1><p>This document provides a comprehensive reference for all configuration options available in Evolve. Understanding these configurations will help you tailor Evolve&#39;s behavior to your specific needs, whether you&#39;re running an aggregator, a full node, or a light client.</p><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#da-only-sync-mode">DA-Only Sync Mode</a></li><li><a href="#configs">Introduction to Configurations</a></li><li><a href="#base-configuration">Base Configuration</a><ul><li><a href="#root-directory">Root Directory</a></li><li><a href="#database-path">Database Path</a></li><li><a href="#chain-id">Chain ID</a></li></ul></li><li><a href="#node-configuration-node">Node Configuration (<code>node</code>)</a><ul><li><a href="#aggregator-mode">Aggregator Mode</a></li><li><a href="#based-sequencer-mode">Based Sequencer Mode</a></li><li><a href="#light-client-mode">Light Client Mode</a></li><li><a href="#block-time">Block Time</a></li><li><a href="#maximum-pending-headers-and-data">Maximum Pending Headers and Data</a></li><li><a href="#lazy-mode-lazy-aggregator">Lazy Mode (Lazy Aggregator)</a></li><li><a href="#lazy-block-interval">Lazy Block Interval</a></li><li><a href="#scrape-interval">Scrape Interval</a></li><li><a href="#catchup-timeout">Catchup Timeout</a></li><li><a href="#readiness-window-seconds">Readiness Window Seconds</a></li><li><a href="#readiness-max-blocks-behind">Readiness Max Blocks Behind</a></li></ul></li><li><a href="#pruning-configuration-pruning">Pruning Configuration (<code>pruning</code>)</a></li><li><a href="#data-availability-configuration-da">Data Availability Configuration (<code>da</code>)</a><ul><li><a href="#da-service-address">DA Service Address</a></li><li><a href="#da-authentication-token">DA Authentication Token</a></li><li><a href="#da-submit-options">DA Submit Options</a></li><li><a href="#da-signing-addresses">DA Signing Addresses</a></li><li><a href="#da-max-submit-attempts">DA Max Submit Attempts</a></li><li><a href="#da-namespace">DA Namespace</a></li><li><a href="#da-data-namespace">DA Data Namespace</a></li><li><a href="#da-forced-inclusion-namespace">DA Forced Inclusion Namespace</a></li><li><a href="#da-block-time">DA Block Time</a></li><li><a href="#da-mempool-ttl">DA Mempool TTL</a></li><li><a href="#da-request-timeout">DA Request Timeout</a></li><li><a href="#da-batching-strategy">DA Batching Strategy</a></li><li><a href="#da-batch-size-threshold">DA Batch Size Threshold</a></li><li><a href="#da-batch-max-delay">DA Batch Max Delay</a></li><li><a href="#da-batch-min-items">DA Batch Min Items</a></li></ul></li><li><a href="#p2p-configuration-p2p">P2P Configuration (<code>p2p</code>)</a><ul><li><a href="#p2p-listen-address">P2P Listen Address</a></li><li><a href="#p2p-peers">P2P Peers</a></li><li><a href="#p2p-blocked-peers">P2P Blocked Peers</a></li><li><a href="#p2p-allowed-peers">P2P Allowed Peers</a></li></ul></li><li><a href="#rpc-configuration-rpc">RPC Configuration (<code>rpc</code>)</a><ul><li><a href="#rpc-server-address">RPC Server Address</a></li><li><a href="#enable-da-visualization">Enable DA Visualization</a></li><li><a href="#health-endpoints">Health Endpoints</a></li></ul></li><li><a href="#instrumentation-configuration-instrumentation">Instrumentation Configuration (<code>instrumentation</code>)</a><ul><li><a href="#enable-prometheus-metrics">Enable Prometheus Metrics</a></li><li><a href="#prometheus-listen-address">Prometheus Listen Address</a></li><li><a href="#maximum-open-connections">Maximum Open Connections</a></li><li><a href="#enable-pprof-profiling">Enable Pprof Profiling</a></li><li><a href="#pprof-listen-address">Pprof Listen Address</a></li><li><a href="#enable-tracing">Enable Tracing</a></li><li><a href="#tracing-endpoint">Tracing Endpoint</a></li><li><a href="#tracing-service-name">Tracing Service Name</a></li><li><a href="#tracing-sample-rate">Tracing Sample Rate</a></li></ul></li><li><a href="#logging-configuration-log">Logging Configuration (<code>log</code>)</a><ul><li><a href="#log-level">Log Level</a></li><li><a href="#log-format">Log Format</a></li><li><a href="#log-trace-stack-traces">Log Trace (Stack Traces)</a></li></ul></li><li><a href="#signer-configuration-signer">Signer Configuration (<code>signer</code>)</a><ul><li><a href="#signer-type">Signer Type</a></li><li><a href="#signer-path">Signer Path</a></li><li><a href="#signer-passphrase-file">Signer Passphrase File</a></li></ul></li><li><a href="#raft-configuration-raft">Raft Configuration (<code>raft</code>)</a><ul><li><a href="#enable-raft">Enable Raft</a></li><li><a href="#raft-node-id">Raft Node ID</a></li><li><a href="#raft-address">Raft Address</a></li><li><a href="#raft-directory">Raft Directory</a></li><li><a href="#raft-bootstrap">Raft Bootstrap</a></li><li><a href="#raft-peers">Raft Peers</a></li><li><a href="#raft-snap-count">Raft Snap Count</a></li><li><a href="#raft-send-timeout">Raft Send Timeout</a></li><li><a href="#raft-heartbeat-timeout">Raft Heartbeat Timeout</a></li><li><a href="#raft-leader-lease-timeout">Raft Leader Lease Timeout</a></li></ul></li></ul><h2 id="da-only-sync-mode" tabindex="-1">DA-Only Sync Mode <a class="header-anchor" href="#da-only-sync-mode" aria-label="Permalink to &quot;DA-Only Sync Mode&quot;">​</a></h2><p>Evolve supports running nodes that sync exclusively from the Data Availability (DA) layer without participating in P2P networking. This mode is useful for:</p><ul><li><strong>Pure DA followers</strong>: Nodes that only need the canonical chain data from DA</li><li><strong>Resource optimization</strong>: Reducing network overhead by avoiding P2P gossip</li><li><strong>Simplified deployment</strong>: No need to configure or maintain P2P peer connections</li><li><strong>Isolated environments</strong>: Nodes that should not participate in P2P communication</li></ul><p><strong>To enable DA-only sync mode:</strong></p><ol><li><p><strong>Leave P2P peers empty</strong> (default behavior):</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p2p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  peers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Empty or omit this field entirely</span></span></code></pre></div></li><li><p><strong>Configure DA connection</strong> (required):</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  address</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-da-service:port&quot;</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  namespace</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-namespace&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # ... other DA configuration</span></span></code></pre></div></li><li><p><strong>Optional</strong>: You can still configure P2P listen address for potential future connections, but without peers, no P2P networking will occur.</p></li></ol><p>When running in DA-only mode, the node will:</p><ul><li>✅ Sync blocks and headers from the DA layer</li><li>✅ Validate transactions and maintain state</li><li>✅ Serve RPC requests</li><li>❌ Not participate in P2P gossip or peer discovery</li><li>❌ Not share blocks with other nodes via P2P</li><li>❌ Not receive transactions via P2P (only from direct RPC submission)</li></ul><h2 id="configs" tabindex="-1">Configs <a class="header-anchor" href="#configs" aria-label="Permalink to &quot;Configs&quot;">​</a></h2><p>Evolve configurations can be managed through a YAML file (typically <code>evnode.yml</code> located in <code>~/.evolve/config/</code> or <code>&lt;your_home_dir&gt;/config/</code>) and command-line flags. The system prioritizes configurations in the following order (highest priority first):</p><ol><li><strong>Command-line flags:</strong> Override all other settings.</li><li><strong>YAML configuration file:</strong> Values specified in the <code>config.yaml</code> file.</li><li><strong>Default values:</strong> Predefined defaults within Evolve.</li></ol><p>Environment variables can also be used, typically prefixed with your executable&#39;s name (e.g., <code>YOURAPP_CHAIN_ID=&quot;my-chain&quot;</code>).</p><h2 id="base-configuration" tabindex="-1">Base Configuration <a class="header-anchor" href="#base-configuration" aria-label="Permalink to &quot;Base Configuration&quot;">​</a></h2><p>These are fundamental settings for your Evolve node.</p><h3 id="root-directory" tabindex="-1">Root Directory <a class="header-anchor" href="#root-directory" aria-label="Permalink to &quot;Root Directory&quot;">​</a></h3><p><strong>Description:</strong> The root directory where Evolve stores its data, including the database and configuration files. This is a foundational setting that dictates where all other file paths are resolved from.</p><p><strong>YAML:</strong> This option is not set within the YAML configuration file itself, as it specifies the location <em>of</em> the configuration file and other application data.</p><p><strong>Command-line Flag:</strong><code>--home &lt;path&gt;</code><em>Example:</em> <code>--home /mnt/data/evolve_node</code><em>Default:</em> <code>~/.evolve</code> (or a directory derived from the application name if <code>defaultHome</code> is customized). <em>Constant:</em> <code>FlagRootDir</code></p><h3 id="database-path" tabindex="-1">Database Path <a class="header-anchor" href="#database-path" aria-label="Permalink to &quot;Database Path&quot;">​</a></h3><p><strong>Description:</strong> The path, relative to the Root Directory, where the Evolve database will be stored. This database contains blockchain state, blocks, and other critical node data.</p><p><strong>YAML:</strong> Set this in your configuration file at the top level:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">db_path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;data&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.db_path &lt;path&gt;</code><em>Example:</em> <code>--evnode.db_path &quot;node_db&quot;</code><em>Default:</em> <code>&quot;data&quot;</code><em>Constant:</em> <code>FlagDBPath</code></p><h3 id="chain-id" tabindex="-1">Chain ID <a class="header-anchor" href="#chain-id" aria-label="Permalink to &quot;Chain ID&quot;">​</a></h3><p><strong>Description:</strong> The unique identifier for your chain. This ID is used to differentiate your network from others and is crucial for network communication and transaction validation.</p><p><strong>YAML:</strong> Set this in your configuration file at the top level:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">chain_id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;my-evolve-chain&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--chain_id &lt;string&gt;</code><em>Example:</em> <code>--chain_id &quot;super_rollup_testnet_v1&quot;</code><em>Default:</em> <code>&quot;evolve&quot;</code><em>Constant:</em> <code>FlagChainID</code></p><h2 id="node-configuration-node" tabindex="-1">Node Configuration (<code>node</code>) <a class="header-anchor" href="#node-configuration-node" aria-label="Permalink to &quot;Node Configuration (`node`)&quot;">​</a></h2><p>Settings related to the core behavior of the Evolve node, including its mode of operation and block production parameters.</p><p><strong>YAML Section:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # ... node configurations ...</span></span></code></pre></div><h3 id="aggregator-mode" tabindex="-1">Aggregator Mode <a class="header-anchor" href="#aggregator-mode" aria-label="Permalink to &quot;Aggregator Mode&quot;">​</a></h3><p><strong>Description:</strong> If true, the node runs in aggregator mode. Aggregators are responsible for producing blocks by collecting transactions, ordering them, and proposing them to the network.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  aggregator</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.node.aggregator</code> (boolean, presence enables it) <em>Example:</em> <code>--evnode.node.aggregator</code><em>Default:</em> <code>false</code><em>Constant:</em> <code>FlagAggregator</code></p><h3 id="based-sequencer-mode" tabindex="-1">Based Sequencer Mode <a class="header-anchor" href="#based-sequencer-mode" aria-label="Permalink to &quot;Based Sequencer Mode&quot;">​</a></h3><p><strong>Description:</strong> If true, the node runs in based sequencer mode. In this mode the aggregator only processes transactions fetched from the DA forced inclusion namespace rather than from the P2P mempool. Requires aggregator mode to be enabled.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  based_sequencer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.node.based_sequencer</code> (boolean, presence enables it) <em>Example:</em> <code>--evnode.node.based_sequencer</code><em>Default:</em> <code>false</code><em>Constant:</em> <code>FlagBasedSequencer</code></p><h3 id="light-client-mode" tabindex="-1">Light Client Mode <a class="header-anchor" href="#light-client-mode" aria-label="Permalink to &quot;Light Client Mode&quot;">​</a></h3><p><strong>Description:</strong> If true, the node runs in light client mode. Light clients rely on full nodes for block headers and state information, offering a lightweight way to interact with the chain without storing all data.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  light</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.node.light</code> (boolean, presence enables it) <em>Example:</em> <code>--evnode.node.light</code><em>Default:</em> <code>false</code><em>Constant:</em> <code>FlagLight</code></p><h3 id="block-time" tabindex="-1">Block Time <a class="header-anchor" href="#block-time" aria-label="Permalink to &quot;Block Time&quot;">​</a></h3><p><strong>Description:</strong> The target time interval between consecutive blocks produced by an aggregator. This duration (e.g., &quot;500ms&quot;, &quot;1s&quot;, &quot;5s&quot;) dictates the pace of block production.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  block_time</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1s&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.node.block_time &lt;duration&gt;</code><em>Example:</em> <code>--evnode.node.block_time 2s</code><em>Default:</em> <code>&quot;1s&quot;</code><em>Constant:</em> <code>FlagBlockTime</code></p><h3 id="maximum-pending-headers-and-data" tabindex="-1">Maximum Pending Headers and Data <a class="header-anchor" href="#maximum-pending-headers-and-data" aria-label="Permalink to &quot;Maximum Pending Headers and Data&quot;">​</a></h3><p><strong>Description:</strong> The maximum number of headers or data items that can be pending Data Availability (DA) confirmation. When this limit is reached, the aggregator pauses block production until some are confirmed on the DA layer. Use 0 for no limit. This helps manage resource usage and DA layer capacity.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  max_pending_headers_and_data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.node.max_pending_headers_and_data &lt;uint64&gt;</code><em>Example:</em> <code>--evnode.node.max_pending_headers_and_data 50</code><em>Default:</em> <code>0</code> (no limit) <em>Constant:</em> <code>FlagMaxPendingHeadersAndData</code></p><h3 id="lazy-mode-lazy-aggregator" tabindex="-1">Lazy Mode (Lazy Aggregator) <a class="header-anchor" href="#lazy-mode-lazy-aggregator" aria-label="Permalink to &quot;Lazy Mode (Lazy Aggregator)&quot;">​</a></h3><p><strong>Description:</strong> Enables lazy aggregation mode. In this mode, blocks are produced only when new transactions are available in the mempool or after the <code>lazy_block_interval</code> has passed. This optimizes resource usage by avoiding the creation of empty blocks during periods of inactivity.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  lazy_mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.node.lazy_mode</code> (boolean, presence enables it) <em>Example:</em> <code>--evnode.node.lazy_mode</code><em>Default:</em> <code>false</code><em>Constant:</em> <code>FlagLazyAggregator</code></p><h3 id="lazy-block-interval" tabindex="-1">Lazy Block Interval <a class="header-anchor" href="#lazy-block-interval" aria-label="Permalink to &quot;Lazy Block Interval&quot;">​</a></h3><p><strong>Description:</strong> The maximum time interval between blocks when running in lazy aggregation mode (<code>lazy_mode</code>). This ensures that blocks are produced periodically even if there are no new transactions, keeping the chain active. This value is generally larger than <code>block_time</code>.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  lazy_block_interval</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;30s&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.node.lazy_block_interval &lt;duration&gt;</code><em>Example:</em> <code>--evnode.node.lazy_block_interval 2m</code><em>Default:</em> <code>&quot;1m&quot;</code><em>Constant:</em> <code>FlagLazyBlockTime</code></p><h3 id="scrape-interval" tabindex="-1">Scrape Interval <a class="header-anchor" href="#scrape-interval" aria-label="Permalink to &quot;Scrape Interval&quot;">​</a></h3><p><strong>Description:</strong> The interval at which the reaper polls the execution layer for new transactions. Lower values reduce transaction detection latency but increase RPC load on the execution client.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  scrape_interval</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1s&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.node.scrape_interval &lt;duration&gt;</code><em>Example:</em> <code>--evnode.node.scrape_interval 500ms</code><em>Default:</em> <code>&quot;1s&quot;</code><em>Constant:</em> <code>FlagScrapeInterval</code></p><h3 id="catchup-timeout" tabindex="-1">Catchup Timeout <a class="header-anchor" href="#catchup-timeout" aria-label="Permalink to &quot;Catchup Timeout&quot;">​</a></h3><p><strong>Description:</strong> When set to a non-zero duration, the aggregator syncs from DA and P2P before producing blocks. The value specifies how long to wait for P2P catchup after DA sync completes. Requires aggregator mode. Mutually exclusive with Raft consensus.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  catchup_timeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;30s&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.node.catchup_timeout &lt;duration&gt;</code><em>Example:</em> <code>--evnode.node.catchup_timeout 1m</code><em>Default:</em> <code>&quot;0s&quot;</code> (disabled) <em>Constant:</em> <code>FlagCatchupTimeout</code></p><h3 id="readiness-window-seconds" tabindex="-1">Readiness Window Seconds <a class="header-anchor" href="#readiness-window-seconds" aria-label="Permalink to &quot;Readiness Window Seconds&quot;">​</a></h3><p><strong>Description:</strong> The time window in seconds used to calculate how many blocks behind the node can be and still be considered ready. The actual block threshold is derived by dividing this window by the block time. Default is 15 seconds.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  readiness_window_seconds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">15</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.node.readiness_window_seconds &lt;uint64&gt;</code><em>Example:</em> <code>--evnode.node.readiness_window_seconds 30</code><em>Default:</em> <code>15</code><em>Constant:</em> <code>FlagReadinessWindowSeconds</code></p><h3 id="readiness-max-blocks-behind" tabindex="-1">Readiness Max Blocks Behind <a class="header-anchor" href="#readiness-max-blocks-behind" aria-label="Permalink to &quot;Readiness Max Blocks Behind&quot;">​</a></h3><p><strong>Description:</strong> Explicit override for how many blocks behind best-known head the node can be and still be considered ready. When set to 0, the value is calculated automatically from <code>readiness_window_seconds</code> and the block time. Override this to set an absolute block count instead of a time-based window.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  readiness_max_blocks_behind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">15</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.node.readiness_max_blocks_behind &lt;uint64&gt;</code><em>Example:</em> <code>--evnode.node.readiness_max_blocks_behind 30</code><em>Default:</em> <code>0</code> (calculated from <code>readiness_window_seconds</code>) <em>Constant:</em> <code>FlagReadinessMaxBlocksBehind</code></p><h2 id="pruning-configuration-pruning" tabindex="-1">Pruning Configuration (<code>pruning</code>) <a class="header-anchor" href="#pruning-configuration-pruning" aria-label="Permalink to &quot;Pruning Configuration (`pruning`)&quot;">​</a></h2><p><strong>Description:</strong> Controls automatic pruning of stored block data and metadata from the local store. Pruning helps manage disk space by periodically removing old blocks and their associated state, while keeping a recent window of history for validation and queries.</p><p><strong>Pruning Modes:</strong></p><ul><li><strong><code>disabled</code></strong> (default): Archive mode - keeps all blocks and metadata indefinitely</li><li><strong><code>metadata</code></strong>: Prunes only state metadata (execution state snapshots), keeps all blocks</li><li><strong><code>all</code></strong>: Prunes both blocks (headers, data, signatures) and metadata</li></ul><p><strong>How Pruning Works:</strong></p><p>When pruning is enabled, the pruner runs at the configured interval and removes data beyond the retention window (<code>pruning_keep_recent</code>). The system uses intelligent batching to avoid overwhelming the node:</p><ul><li><strong>Batch sizes are automatically calculated</strong> based on your <code>pruning_interval</code> and <code>block_time</code></li><li><strong>Catch-up mode</strong>: When first enabling pruning on an existing node, smaller batches (2× blocks per interval) are used to gradually catch up without impacting performance</li><li><strong>Normal mode</strong>: Once caught up, larger batches (4× blocks per interval) are used for efficient maintenance</li><li><strong>Progress tracking</strong>: Pruning progress is saved after each batch, so restarts don&#39;t lose progress</li></ul><p><strong>Batch Size Examples:</strong></p><p>With default settings (15 minute interval, 1 second blocks):</p><ul><li>Catch-up: ~1,800 blocks per run</li><li>Normal: ~3,600 blocks per run</li></ul><p>With high-throughput chain (15 minute interval, 100ms blocks):</p><ul><li>Catch-up: ~18,000 blocks per run</li><li>Normal: ~36,000 blocks per run</li></ul><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">pruning</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  pruning_mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;all&quot;</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  pruning_keep_recent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100000</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  pruning_interval</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;15m&quot;</span></span></code></pre></div><p><strong>Command-line Flags:</strong></p><ul><li><p><code>--evnode.pruning.pruning_mode &lt;string&gt;</code></p><ul><li><em>Description:</em> Pruning mode: &#39;disabled&#39; (keep all), &#39;metadata&#39; (prune state only), or &#39;all&#39; (prune blocks and state)</li><li><em>Example:</em> <code>--evnode.pruning.pruning_mode all</code></li><li><em>Default:</em> <code>&quot;disabled&quot;</code></li></ul></li><li><p><code>--evnode.pruning.pruning_keep_recent &lt;uint64&gt;</code></p><ul><li><em>Description:</em> Number of most recent blocks/metadata to retain when pruning is enabled. Must be &gt; 0 when pruning is enabled.</li><li><em>Example:</em> <code>--evnode.pruning.pruning_keep_recent 100000</code></li><li><em>Default:</em> <code>0</code></li></ul></li><li><p><code>--evnode.pruning.pruning_interval &lt;duration&gt;</code></p><ul><li><em>Description:</em> How often to run the pruning process. Must be &gt;= block_time when pruning is enabled. Larger intervals allow larger batch sizes.</li><li><em>Example:</em> <code>--evnode.pruning.pruning_interval 15m</code></li><li><em>Default:</em> <code>0</code> (disabled)</li></ul></li></ul><p><em>Constants:</em> <code>FlagPruningMode</code>, <code>FlagPruningKeepRecent</code>, <code>FlagPruningInterval</code></p><p><strong>Important Notes:</strong></p><ul><li>When DA is enabled (DA address is configured), pruning only removes blocks that have been confirmed on the DA layer (for mode <code>all</code>) to ensure data safety</li><li>When DA is not enabled (no DA address configured), pruning proceeds based solely on store height, allowing nodes without DA to manage disk space</li><li>The first pruning run after enabling may take several cycles to catch up, processing data in smaller batches</li><li>Pruning cannot be undone - ensure your retention window is sufficient for your use case</li><li>For production deployments, consider keeping at least 100,000 recent blocks</li><li>The pruning interval should be balanced with your disk space growth rate</li></ul><h2 id="data-availability-configuration-da" tabindex="-1">Data Availability Configuration (<code>da</code>) <a class="header-anchor" href="#data-availability-configuration-da" aria-label="Permalink to &quot;Data Availability Configuration (`da`)&quot;">​</a></h2><p>Parameters for connecting and interacting with the Data Availability (DA) layer, which Evolve uses to publish block data.</p><p><strong>YAML Section:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # ... DA configurations ...</span></span></code></pre></div><h3 id="da-service-address" tabindex="-1">DA Service Address <a class="header-anchor" href="#da-service-address" aria-label="Permalink to &quot;DA Service Address&quot;">​</a></h3><p><strong>Description:</strong> The network address (host:port) of the Data Availability layer service. Evolve connects to this endpoint to submit and retrieve block data.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  address</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;localhost:26659&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.address &lt;string&gt;</code><em>Example:</em> <code>--evnode.da.address 192.168.1.100:26659</code><em>Default:</em> <code>&quot;http://localhost:7980&quot;</code><em>Constant:</em> <code>FlagDAAddress</code></p><h3 id="da-authentication-token" tabindex="-1">DA Authentication Token <a class="header-anchor" href="#da-authentication-token" aria-label="Permalink to &quot;DA Authentication Token&quot;">​</a></h3><p><strong>Description:</strong> The authentication token required to interact with the DA layer service, if the service mandates authentication.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  auth_token</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;YOUR_DA_AUTH_TOKEN&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.auth_token &lt;string&gt;</code><em>Example:</em> <code>--evnode.da.auth_token mysecrettoken</code><em>Default:</em> <code>&quot;&quot;</code> (empty) <em>Constant:</em> <code>FlagDAAuthToken</code></p><h3 id="da-submit-options" tabindex="-1">DA Submit Options <a class="header-anchor" href="#da-submit-options" aria-label="Permalink to &quot;DA Submit Options&quot;">​</a></h3><p><strong>Description:</strong> Additional options passed to the DA layer when submitting data. The format and meaning of these options depend on the specific DA implementation being used. For example, with Celestia, this can include custom gas settings or other submission parameters in JSON format.</p><p><strong>Note:</strong> If you configure multiple signing addresses (see <a href="#da-signing-addresses">DA Signing Addresses</a>), the selected signing address will be automatically merged into these options as a JSON field <code>signer_address</code> (matching Celestia&#39;s TxConfig schema). If the base options are already valid JSON, the signing address is added to the existing object; otherwise, a new JSON object is created.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  submit_options</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;{&quot;key&quot;:&quot;value&quot;}&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Example, format depends on DA layer</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.submit_options &lt;string&gt;</code><em>Example:</em> <code>--evnode.da.submit_options &#39;{&quot;custom_param&quot;:true}&#39;</code><em>Default:</em> <code>&quot;&quot;</code> (empty) <em>Constant:</em> <code>FlagDASubmitOptions</code></p><h3 id="da-signing-addresses" tabindex="-1">DA Signing Addresses <a class="header-anchor" href="#da-signing-addresses" aria-label="Permalink to &quot;DA Signing Addresses&quot;">​</a></h3><p><strong>Description:</strong> A comma-separated list of signing addresses to use for DA blob submissions. When multiple addresses are provided, they will be used in round-robin fashion to prevent sequence mismatches that can occur with high-throughput Cosmos SDK-based DA layers. This is particularly useful for Celestia when submitting many transactions concurrently.</p><p>Each submission will select the next address in the list, and that address will be automatically added to the <code>submit_options</code> as <code>signer_address</code>. This ensures that the DA layer (e.g., celestia-node) uses the specified account for signing that particular blob submission.</p><p><strong>Setup Requirements:</strong></p><ul><li>All addresses must be loaded into the DA node&#39;s keyring and have sufficient funds for transaction fees</li><li>For Celestia, see the guide on setting up multiple accounts in the DA node documentation</li></ul><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  signing_addresses</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;celestia1abc123...&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;celestia1def456...&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;celestia1ghi789...&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.signing_addresses &lt;string&gt;</code><em>Example:</em> <code>--evnode.da.signing_addresses celestia1abc...,celestia1def...,celestia1ghi...</code><em>Default:</em> <code>[]</code> (empty, uses default DA node behavior) <em>Constant:</em> <code>FlagDASigningAddresses</code></p><p><strong>Behavior:</strong></p><ul><li>If no signing addresses are configured, submissions use the DA layer&#39;s default signing behavior</li><li>If one address is configured, all submissions use that address</li><li>If multiple addresses are configured, they are used in round-robin order to distribute the load and prevent nonce/sequence conflicts</li><li>The address selection is thread-safe for concurrent submissions</li></ul><h3 id="da-max-submit-attempts" tabindex="-1">DA Max Submit Attempts <a class="header-anchor" href="#da-max-submit-attempts" aria-label="Permalink to &quot;DA Max Submit Attempts&quot;">​</a></h3><p><strong>Description:</strong> The maximum number of attempts to submit data to the DA layer before giving up. Higher values provide more resilience against transient DA failures but can delay error reporting.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  max_submit_attempts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.max_submit_attempts &lt;int&gt;</code><em>Example:</em> <code>--evnode.da.max_submit_attempts 10</code><em>Default:</em> <code>30</code><em>Constant:</em> <code>FlagDAMaxSubmitAttempts</code></p><h3 id="da-namespace" tabindex="-1">DA Namespace <a class="header-anchor" href="#da-namespace" aria-label="Permalink to &quot;DA Namespace&quot;">​</a></h3><p><strong>Description:</strong> The namespace ID used when submitting blobs (block data) to the DA layer. This helps segregate data from different chains or applications on a shared DA layer.</p><p><strong>Note:</strong> If only <code>namespace</code> is provided, it will be used for both headers and data, otherwise the <code>data_namespace</code> will be used for data. Doing so allows speeding up light clients.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  namespace</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;MY_UNIQUE_NAMESPACE_ID&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.namespace &lt;string&gt;</code><em>Example:</em> <code>--evnode.da.namespace 0x1234567890abcdef</code><em>Default:</em> randomly generated at startup <em>Constant:</em> <code>FlagDANamespace</code></p><h3 id="da-data-namespace" tabindex="-1">DA Data Namespace <a class="header-anchor" href="#da-data-namespace" aria-label="Permalink to &quot;DA Data Namespace&quot;">​</a></h3><p><strong>Description:</strong> The namespace ID specifically for submitting transaction data to the DA layer. Transaction data is submitted separately from headers, enabling nodes to sync only the data they need. The namespace value is encoded by the node to ensure proper formatting and compatibility with the DA layer.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  data_namespace</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;DATA_NAMESPACE_ID&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.data_namespace &lt;string&gt;</code><em>Example:</em> <code>--evnode.da.data_namespace my_data_namespace</code><em>Default:</em> <code>&quot;&quot;</code> (falls back to <code>namespace</code> if not set) <em>Constant:</em> <code>FlagDADataNamespace</code></p><h3 id="da-forced-inclusion-namespace" tabindex="-1">DA Forced Inclusion Namespace <a class="header-anchor" href="#da-forced-inclusion-namespace" aria-label="Permalink to &quot;DA Forced Inclusion Namespace&quot;">​</a></h3><p><strong>Description:</strong> The namespace ID used for forced inclusion transactions on the DA layer. When set, the based sequencer will fetch transactions from this namespace. Required when running in based sequencer mode.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  forced_inclusion_namespace</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;FORCED_INCLUSION_NAMESPACE_ID&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.forced_inclusion_namespace &lt;string&gt;</code><em>Example:</em> <code>--evnode.da.forced_inclusion_namespace 0xabcdef1234567890</code><em>Default:</em> <code>&quot;&quot;</code> (empty) <em>Constant:</em> <code>FlagDAForcedInclusionNamespace</code></p><h3 id="da-block-time" tabindex="-1">DA Block Time <a class="header-anchor" href="#da-block-time" aria-label="Permalink to &quot;DA Block Time&quot;">​</a></h3><p><strong>Description:</strong> The average block time of the Data Availability chain (specified as a duration string, e.g., &quot;15s&quot;, &quot;1m&quot;). This value influences:</p><ul><li>The frequency of DA layer syncing.</li><li>The maximum backoff time for retrying DA submissions.</li><li>Calculation of transaction expiration when multiplied by <code>mempool_ttl</code>.</li></ul><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  block_time</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;6s&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.block_time &lt;duration&gt;</code><em>Example:</em> <code>--evnode.da.block_time 12s</code><em>Default:</em> <code>&quot;6s&quot;</code><em>Constant:</em> <code>FlagDABlockTime</code></p><h3 id="da-mempool-ttl" tabindex="-1">DA Mempool TTL <a class="header-anchor" href="#da-mempool-ttl" aria-label="Permalink to &quot;DA Mempool TTL&quot;">​</a></h3><p><strong>Description:</strong> The number of DA blocks after which a transaction submitted to the DA layer is considered expired and potentially dropped from the DA layer&#39;s mempool. This also controls the retry backoff timing for DA submissions.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  mempool_ttl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.mempool_ttl &lt;uint64&gt;</code><em>Example:</em> <code>--evnode.da.mempool_ttl 30</code><em>Default:</em> <code>0</code><em>Constant:</em> <code>FlagDAMempoolTTL</code></p><h3 id="da-request-timeout" tabindex="-1">DA Request Timeout <a class="header-anchor" href="#da-request-timeout" aria-label="Permalink to &quot;DA Request Timeout&quot;">​</a></h3><p><strong>Description:</strong> Per-request timeout applied to DA <code>GetIDs</code> and <code>Get</code> RPC calls while retrieving blobs. Increase this value if your DA endpoint has high latency to avoid premature failures; decrease it to make the syncer fail fast and free resources sooner when the DA node becomes unresponsive.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  request_timeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;30s&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.request_timeout &lt;duration&gt;</code><em>Example:</em> <code>--evnode.da.request_timeout 45s</code><em>Default:</em> <code>&quot;1m&quot;</code><em>Constant:</em> <code>FlagDARequestTimeout</code></p><h3 id="da-batching-strategy" tabindex="-1">DA Batching Strategy <a class="header-anchor" href="#da-batching-strategy" aria-label="Permalink to &quot;DA Batching Strategy&quot;">​</a></h3><p><strong>Description:</strong> Controls how blocks are batched before submission to the DA layer. Different strategies offer trade-offs between latency, cost efficiency, and throughput. All strategies pass through the DA submitter which performs additional size checks and may further split batches that exceed the DA layer&#39;s blob size limit.</p><p>Available strategies:</p><ul><li><strong><code>immediate</code></strong>: Submits as soon as any items are available. Best for low-latency requirements where cost is not a concern.</li><li><strong><code>size</code></strong>: Waits until the batch reaches a size threshold (fraction of max blob size). Best for maximizing blob utilization and minimizing costs when latency is flexible.</li><li><strong><code>time</code></strong>: Waits for a time interval before submitting. Provides predictable submission timing aligned with DA block times.</li><li><strong><code>adaptive</code></strong>: Balances between size and time constraints—submits when either the size threshold is reached OR the max delay expires. Recommended for most production deployments as it optimizes both cost and latency.</li></ul><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  batching_strategy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;time&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.batching_strategy &lt;string&gt;</code><em>Example:</em> <code>--evnode.da.batching_strategy adaptive</code><em>Default:</em> <code>&quot;time&quot;</code><em>Constant:</em> <code>FlagDABatchingStrategy</code></p><h3 id="da-batch-size-threshold" tabindex="-1">DA Batch Size Threshold <a class="header-anchor" href="#da-batch-size-threshold" aria-label="Permalink to &quot;DA Batch Size Threshold&quot;">​</a></h3><p><strong>Description:</strong> The minimum blob size threshold (as a fraction of the maximum blob size, between 0.0 and 1.0) before submitting a batch. Only applies to the <code>size</code> and <code>adaptive</code> strategies. For example, a value of 0.8 means the batch will be submitted when it reaches 80% of the maximum blob size.</p><p>Higher values maximize blob utilization and reduce costs but may increase latency. Lower values reduce latency but may result in less efficient blob usage.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  batch_size_threshold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.8</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.batch_size_threshold &lt;float64&gt;</code><em>Example:</em> <code>--evnode.da.batch_size_threshold 0.9</code><em>Default:</em> <code>0.8</code> (80% of max blob size) <em>Constant:</em> <code>FlagDABatchSizeThreshold</code></p><h3 id="da-batch-max-delay" tabindex="-1">DA Batch Max Delay <a class="header-anchor" href="#da-batch-max-delay" aria-label="Permalink to &quot;DA Batch Max Delay&quot;">​</a></h3><p><strong>Description:</strong> The maximum time to wait before submitting a batch regardless of size. Applies to the <code>time</code> and <code>adaptive</code> strategies. Lower values reduce latency but may increase costs due to smaller batches. This value is typically aligned with the DA chain&#39;s block time to ensure submissions land in consecutive blocks.</p><p>When set to 0, defaults to the DA BlockTime value.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  batch_max_delay</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;6s&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.batch_max_delay &lt;duration&gt;</code><em>Example:</em> <code>--evnode.da.batch_max_delay 12s</code><em>Default:</em> <code>0</code> (uses DA BlockTime) <em>Constant:</em> <code>FlagDABatchMaxDelay</code></p><h3 id="da-batch-min-items" tabindex="-1">DA Batch Min Items <a class="header-anchor" href="#da-batch-min-items" aria-label="Permalink to &quot;DA Batch Min Items&quot;">​</a></h3><p><strong>Description:</strong> The minimum number of items (headers or data) to accumulate before considering submission. This helps avoid submitting single items when more are expected soon, improving batching efficiency. All strategies respect this minimum.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">da</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  batch_min_items</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.da.batch_min_items &lt;uint64&gt;</code><em>Example:</em> <code>--evnode.da.batch_min_items 5</code><em>Default:</em> <code>1</code><em>Constant:</em> <code>FlagDABatchMinItems</code></p><h2 id="p2p-configuration-p2p" tabindex="-1">P2P Configuration (<code>p2p</code>) <a class="header-anchor" href="#p2p-configuration-p2p" aria-label="Permalink to &quot;P2P Configuration (`p2p`)&quot;">​</a></h2><p>Settings for peer-to-peer networking, enabling nodes to discover each other, exchange blocks, and share transactions.</p><p><strong>YAML Section:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p2p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # ... P2P configurations ...</span></span></code></pre></div><h3 id="p2p-listen-address" tabindex="-1">P2P Listen Address <a class="header-anchor" href="#p2p-listen-address" aria-label="Permalink to &quot;P2P Listen Address&quot;">​</a></h3><p><strong>Description:</strong> The network address (host:port) on which the Evolve node will listen for incoming P2P connections from other nodes.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p2p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  listen_address</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.0.0.0:7676&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.p2p.listen_address &lt;string&gt;</code><em>Example:</em> <code>--evnode.p2p.listen_address /ip4/127.0.0.1/tcp/26656</code><em>Default:</em> <code>&quot;/ip4/0.0.0.0/tcp/7676&quot;</code><em>Constant:</em> <code>FlagP2PListenAddress</code></p><h3 id="p2p-peers" tabindex="-1">P2P Peers <a class="header-anchor" href="#p2p-peers" aria-label="Permalink to &quot;P2P Peers&quot;">​</a></h3><p><strong>Description:</strong> A comma-separated list of peer addresses (e.g., multiaddresses) that the node will attempt to connect to for bootstrapping its P2P connections. These are often referred to as seed nodes.</p><p><strong>For DA-only sync mode:</strong> Leave this field empty (default) to disable P2P networking entirely. When no peers are configured, the node will sync exclusively from the Data Availability layer without participating in P2P gossip, peer discovery, or block sharing. This is useful for nodes that only need to follow the canonical chain data from DA.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p2p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  peers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/ip4/some_peer_ip/tcp/7676/p2p/PEER_ID1,/ip4/another_peer_ip/tcp/7676/p2p/PEER_ID2&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # For DA-only sync, leave peers empty:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # peers: &quot;&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.p2p.peers &lt;string&gt;</code><em>Example:</em> <code>--evnode.p2p.peers /dns4/seed.example.com/tcp/26656/p2p/12D3KooW...</code><em>Default:</em> <code>&quot;&quot;</code> (empty - enables DA-only sync mode) <em>Constant:</em> <code>FlagP2PPeers</code></p><h3 id="p2p-blocked-peers" tabindex="-1">P2P Blocked Peers <a class="header-anchor" href="#p2p-blocked-peers" aria-label="Permalink to &quot;P2P Blocked Peers&quot;">​</a></h3><p><strong>Description:</strong> A comma-separated list of peer IDs that the node should block from connecting. This can be used to prevent connections from known malicious or problematic peers.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p2p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  blocked_peers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;PEER_ID_TO_BLOCK1,PEER_ID_TO_BLOCK2&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.p2p.blocked_peers &lt;string&gt;</code><em>Example:</em> <code>--evnode.p2p.blocked_peers 12D3KooW...,12D3KooX...</code><em>Default:</em> <code>&quot;&quot;</code> (empty) <em>Constant:</em> <code>FlagP2PBlockedPeers</code></p><h3 id="p2p-allowed-peers" tabindex="-1">P2P Allowed Peers <a class="header-anchor" href="#p2p-allowed-peers" aria-label="Permalink to &quot;P2P Allowed Peers&quot;">​</a></h3><p><strong>Description:</strong> A comma-separated list of peer IDs that the node should exclusively allow connections from. If this list is non-empty, only peers in this list will be able to connect.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p2p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  allowed_peers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;PEER_ID_TO_ALLOW1,PEER_ID_TO_ALLOW2&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.p2p.allowed_peers &lt;string&gt;</code><em>Example:</em> <code>--evnode.p2p.allowed_peers 12D3KooY...,12D3KooZ...</code><em>Default:</em> <code>&quot;&quot;</code> (empty, allow all unless blocked) <em>Constant:</em> <code>FlagP2PAllowedPeers</code></p><h2 id="rpc-configuration-rpc" tabindex="-1">RPC Configuration (<code>rpc</code>) <a class="header-anchor" href="#rpc-configuration-rpc" aria-label="Permalink to &quot;RPC Configuration (`rpc`)&quot;">​</a></h2><p>Settings for the Remote Procedure Call (RPC) server, which allows clients and applications to interact with the Evolve node.</p><p><strong>YAML Section:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">rpc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # ... RPC configurations ...</span></span></code></pre></div><h3 id="rpc-server-address" tabindex="-1">RPC Server Address <a class="header-anchor" href="#rpc-server-address" aria-label="Permalink to &quot;RPC Server Address&quot;">​</a></h3><p><strong>Description:</strong> The network address (host:port) to which the RPC server will bind and listen for incoming requests.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">rpc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  address</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;127.0.0.1:7331&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.rpc.address &lt;string&gt;</code><em>Example:</em> <code>--evnode.rpc.address 0.0.0.0:26657</code><em>Default:</em> <code>&quot;127.0.0.1:7331&quot;</code><em>Constant:</em> <code>FlagRPCAddress</code></p><h3 id="enable-da-visualization" tabindex="-1">Enable DA Visualization <a class="header-anchor" href="#enable-da-visualization" aria-label="Permalink to &quot;Enable DA Visualization&quot;">​</a></h3><p><strong>Description:</strong> If true, enables the Data Availability (DA) visualization endpoints that provide real-time monitoring of blob submissions to the DA layer. This includes a web-based dashboard and REST API endpoints for tracking submission statistics, monitoring DA health, and analyzing blob details. Only aggregator nodes submit data to the DA layer, so this feature is most useful when running in aggregator mode.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">rpc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enable_da_visualization</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.rpc.enable_da_visualization</code> (boolean, presence enables it) <em>Example:</em> <code>--evnode.rpc.enable_da_visualization</code><em>Default:</em> <code>false</code><em>Constant:</em> <code>FlagRPCEnableDAVisualization</code></p><p>See the <a href="./../guides/da/visualizer">DA Visualizer Guide</a> for detailed information on using this feature.</p><h3 id="health-endpoints" tabindex="-1">Health Endpoints <a class="header-anchor" href="#health-endpoints" aria-label="Permalink to &quot;Health Endpoints&quot;">​</a></h3><h4 id="health-live" tabindex="-1"><code>/health/live</code> <a class="header-anchor" href="#health-live" aria-label="Permalink to &quot;`/health/live`&quot;">​</a></h4><p>Returns <code>200 OK</code> if the process is alive and can access the store.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:7331/health/live</span></span></code></pre></div><h4 id="health-ready" tabindex="-1"><code>/health/ready</code> <a class="header-anchor" href="#health-ready" aria-label="Permalink to &quot;`/health/ready`&quot;">​</a></h4><p>Returns <code>200 OK</code> if the node can serve correct data. Checks:</p><ul><li>P2P is listening (if enabled)</li><li>Has synced blocks</li><li>Not too far behind network</li><li>Non-aggregators: has peers</li><li>Aggregators: producing blocks at expected rate</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:7331/health/ready</span></span></code></pre></div><p>Configure these via <a href="#readiness-window-seconds"><code>readiness_window_seconds</code></a> and <a href="#readiness-max-blocks-behind"><code>readiness_max_blocks_behind</code></a> in the node configuration.</p><h2 id="instrumentation-configuration-instrumentation" tabindex="-1">Instrumentation Configuration (<code>instrumentation</code>) <a class="header-anchor" href="#instrumentation-configuration-instrumentation" aria-label="Permalink to &quot;Instrumentation Configuration (`instrumentation`)&quot;">​</a></h2><p>Settings for enabling and configuring metrics and profiling endpoints, useful for monitoring node performance and debugging.</p><p><strong>YAML Section:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">instrumentation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # ... instrumentation configurations ...</span></span></code></pre></div><h3 id="enable-prometheus-metrics" tabindex="-1">Enable Prometheus Metrics <a class="header-anchor" href="#enable-prometheus-metrics" aria-label="Permalink to &quot;Enable Prometheus Metrics&quot;">​</a></h3><p><strong>Description:</strong> If true, enables the Prometheus metrics endpoint, allowing Prometheus to scrape operational data from the Evolve node.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">instrumentation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  prometheus</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.instrumentation.prometheus</code> (boolean, presence enables it) <em>Example:</em> <code>--evnode.instrumentation.prometheus</code><em>Default:</em> <code>false</code><em>Constant:</em> <code>FlagPrometheus</code></p><h3 id="prometheus-listen-address" tabindex="-1">Prometheus Listen Address <a class="header-anchor" href="#prometheus-listen-address" aria-label="Permalink to &quot;Prometheus Listen Address&quot;">​</a></h3><p><strong>Description:</strong> The network address (host:port) where the Prometheus metrics server will listen for scraping requests.</p><p>See <a href="./../guides/metrics">Metrics</a> for more details on what metrics are exposed.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">instrumentation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  prometheus_listen_addr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;:2112&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.instrumentation.prometheus_listen_addr &lt;string&gt;</code><em>Example:</em> <code>--evnode.instrumentation.prometheus_listen_addr 0.0.0.0:9090</code><em>Default:</em> <code>&quot;:26660&quot;</code><em>Constant:</em> <code>FlagPrometheusListenAddr</code></p><h3 id="maximum-open-connections" tabindex="-1">Maximum Open Connections <a class="header-anchor" href="#maximum-open-connections" aria-label="Permalink to &quot;Maximum Open Connections&quot;">​</a></h3><p><strong>Description:</strong> The maximum number of simultaneous connections allowed for the metrics server (e.g., Prometheus endpoint).</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">instrumentation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  max_open_connections</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.instrumentation.max_open_connections &lt;int&gt;</code><em>Example:</em> <code>--evnode.instrumentation.max_open_connections 50</code><em>Default:</em> <code>3</code><em>Constant:</em> <code>FlagMaxOpenConnections</code></p><h3 id="enable-pprof-profiling" tabindex="-1">Enable Pprof Profiling <a class="header-anchor" href="#enable-pprof-profiling" aria-label="Permalink to &quot;Enable Pprof Profiling&quot;">​</a></h3><p><strong>Description:</strong> If true, enables the pprof HTTP endpoint, which provides runtime profiling data for debugging performance issues. Accessing these endpoints can help diagnose CPU and memory usage.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">instrumentation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  pprof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.instrumentation.pprof</code> (boolean, presence enables it) <em>Example:</em> <code>--evnode.instrumentation.pprof</code><em>Default:</em> <code>false</code><em>Constant:</em> <code>FlagPprof</code></p><h3 id="pprof-listen-address" tabindex="-1">Pprof Listen Address <a class="header-anchor" href="#pprof-listen-address" aria-label="Permalink to &quot;Pprof Listen Address&quot;">​</a></h3><p><strong>Description:</strong> The network address (host:port) where the pprof HTTP server will listen for profiling requests.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">instrumentation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  pprof_listen_addr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;localhost:6060&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.instrumentation.pprof_listen_addr &lt;string&gt;</code><em>Example:</em> <code>--evnode.instrumentation.pprof_listen_addr 0.0.0.0:6061</code><em>Default:</em> <code>&quot;:6060&quot;</code><em>Constant:</em> <code>FlagPprofListenAddr</code></p><h3 id="enable-tracing" tabindex="-1">Enable Tracing <a class="header-anchor" href="#enable-tracing" aria-label="Permalink to &quot;Enable Tracing&quot;">​</a></h3><p><strong>Description:</strong> If true, enables OpenTelemetry tracing. Traces are exported via OTLP to the configured endpoint.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">instrumentation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  tracing</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.instrumentation.tracing</code> (boolean, presence enables it) <em>Example:</em> <code>--evnode.instrumentation.tracing</code><em>Default:</em> <code>false</code><em>Constant:</em> <code>FlagTracing</code></p><h3 id="tracing-endpoint" tabindex="-1">Tracing Endpoint <a class="header-anchor" href="#tracing-endpoint" aria-label="Permalink to &quot;Tracing Endpoint&quot;">​</a></h3><p><strong>Description:</strong> The OTLP endpoint (host:port) to which traces are exported. Must be set when tracing is enabled.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">instrumentation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  tracing_endpoint</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;localhost:4318&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.instrumentation.tracing_endpoint &lt;string&gt;</code><em>Example:</em> <code>--evnode.instrumentation.tracing_endpoint otel-collector:4318</code><em>Default:</em> <code>&quot;localhost:4318&quot;</code><em>Constant:</em> <code>FlagTracingEndpoint</code></p><h3 id="tracing-service-name" tabindex="-1">Tracing Service Name <a class="header-anchor" href="#tracing-service-name" aria-label="Permalink to &quot;Tracing Service Name&quot;">​</a></h3><p><strong>Description:</strong> The <code>service.name</code> resource attribute attached to all traces exported by this node. Use this to identify the node in your tracing backend.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">instrumentation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  tracing_service_name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ev-node&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.instrumentation.tracing_service_name &lt;string&gt;</code><em>Example:</em> <code>--evnode.instrumentation.tracing_service_name my-rollup-node</code><em>Default:</em> <code>&quot;ev-node&quot;</code><em>Constant:</em> <code>FlagTracingServiceName</code></p><h3 id="tracing-sample-rate" tabindex="-1">Tracing Sample Rate <a class="header-anchor" href="#tracing-sample-rate" aria-label="Permalink to &quot;Tracing Sample Rate&quot;">​</a></h3><p><strong>Description:</strong> The TraceID ratio-based sampling rate for traces, between 0.0 and 1.0. A value of 1.0 samples all traces; 0.1 samples 10%.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">instrumentation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  tracing_sample_rate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.1</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.instrumentation.tracing_sample_rate &lt;float64&gt;</code><em>Example:</em> <code>--evnode.instrumentation.tracing_sample_rate 0.5</code><em>Default:</em> <code>0.1</code><em>Constant:</em> <code>FlagTracingSampleRate</code></p><h2 id="logging-configuration-log" tabindex="-1">Logging Configuration (<code>log</code>) <a class="header-anchor" href="#logging-configuration-log" aria-label="Permalink to &quot;Logging Configuration (`log`)&quot;">​</a></h2><p>Settings that control the verbosity and format of log output from the Evolve node. These are typically set via global flags.</p><p><strong>YAML Section:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # ... logging configurations ...</span></span></code></pre></div><h3 id="log-level" tabindex="-1">Log Level <a class="header-anchor" href="#log-level" aria-label="Permalink to &quot;Log Level&quot;">​</a></h3><p><strong>Description:</strong> Sets the minimum severity level for log messages to be displayed. Common levels include <code>debug</code>, <code>info</code>, <code>warn</code>, <code>error</code>.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;info&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--log.level &lt;string&gt;</code> (Note: some applications might use a different flag name like <code>--log_level</code>) <em>Example:</em> <code>--log.level debug</code><em>Default:</em> <code>&quot;info&quot;</code><em>Constant:</em> <code>FlagLogLevel</code> (value: &quot;evolve.log.level&quot;, but often overridden by global app flags)</p><h3 id="log-format" tabindex="-1">Log Format <a class="header-anchor" href="#log-format" aria-label="Permalink to &quot;Log Format&quot;">​</a></h3><p><strong>Description:</strong> Sets the format for log output. Common formats include <code>text</code> (human-readable) and <code>json</code> (structured, machine-readable).</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  format</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;text&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--log.format &lt;string&gt;</code> (Note: some applications might use a different flag name like <code>--log_format</code>) <em>Example:</em> <code>--log.format json</code><em>Default:</em> <code>&quot;text&quot;</code><em>Constant:</em> <code>FlagLogFormat</code> (value: &quot;evolve.log.format&quot;, but often overridden by global app flags)</p><h3 id="log-trace-stack-traces" tabindex="-1">Log Trace (Stack Traces) <a class="header-anchor" href="#log-trace-stack-traces" aria-label="Permalink to &quot;Log Trace (Stack Traces)&quot;">​</a></h3><p><strong>Description:</strong> If true, enables the inclusion of stack traces in error logs. This can be very helpful for debugging issues by showing the call stack at the point of an error.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  trace</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--log.trace</code> (boolean, presence enables it; Note: some applications might use a different flag name like <code>--log_trace</code>) <em>Example:</em> <code>--log.trace</code><em>Default:</em> <code>false</code><em>Constant:</em> <code>FlagLogTrace</code> (value: &quot;evolve.log.trace&quot;, but often overridden by global app flags)</p><h2 id="signer-configuration-signer" tabindex="-1">Signer Configuration (<code>signer</code>) <a class="header-anchor" href="#signer-configuration-signer" aria-label="Permalink to &quot;Signer Configuration (`signer`)&quot;">​</a></h2><p>Settings related to the signing mechanism used by the node, particularly for aggregators that need to sign blocks.</p><p><strong>YAML Section:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">signer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # ... signer configurations ...</span></span></code></pre></div><h3 id="signer-type" tabindex="-1">Signer Type <a class="header-anchor" href="#signer-type" aria-label="Permalink to &quot;Signer Type&quot;">​</a></h3><p><strong>Description:</strong> Specifies the type of remote signer to use. Common options might include <code>file</code> (for key files) or <code>grpc</code> (for connecting to a remote signing service).</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">signer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  signer_type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;file&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.signer.signer_type &lt;string&gt;</code><em>Example:</em> <code>--evnode.signer.signer_type grpc</code><em>Default:</em> <code>&quot;file&quot;</code><em>Constant:</em> <code>FlagSignerType</code></p><h3 id="signer-path" tabindex="-1">Signer Path <a class="header-anchor" href="#signer-path" aria-label="Permalink to &quot;Signer Path&quot;">​</a></h3><p><strong>Description:</strong> The path to the signer file (if <code>signer_type</code> is <code>file</code>) or the address of the remote signer service (if <code>signer_type</code> is <code>grpc</code> or similar).</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">signer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  signer_path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/path/to/priv_validator_key.json&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # For file signer</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # signer_path: &quot;localhost:9000&quot; # For gRPC signer</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.signer.signer_path &lt;string&gt;</code><em>Example:</em> <code>--evnode.signer.signer_path ./config</code><em>Default:</em> <code>&quot;config&quot;</code><em>Constant:</em> <code>FlagSignerPath</code></p><h3 id="signer-passphrase-file" tabindex="-1">Signer Passphrase File <a class="header-anchor" href="#signer-passphrase-file" aria-label="Permalink to &quot;Signer Passphrase File&quot;">​</a></h3><p><strong>Description:</strong> Path to a file containing the passphrase for the signer key. Required when using a <code>file</code> signer in aggregator mode. Reading the passphrase from a file avoids exposing it in shell history.</p><p><strong>YAML:</strong> This is not stored in the YAML file. Provide it via flag or environment variable.</p><p><strong>Command-line Flag:</strong><code>--evnode.signer.passphrase_file &lt;string&gt;</code><em>Example:</em> <code>--evnode.signer.passphrase_file /run/secrets/signer_passphrase</code><em>Default:</em> <code>&quot;&quot;</code> (empty) <em>Constant:</em> <code>FlagSignerPassphraseFile</code></p><h2 id="raft-configuration-raft" tabindex="-1">Raft Configuration (<code>raft</code>) <a class="header-anchor" href="#raft-configuration-raft" aria-label="Permalink to &quot;Raft Configuration (`raft`)&quot;">​</a></h2><p>Settings for Raft-based consensus used for leader election and state replication in multi-aggregator deployments. All fields are ignored when <code>raft.enable</code> is false.</p><p><strong>Note:</strong> Raft consensus and <code>catchup_timeout</code> are mutually exclusive. Enabling both will produce a validation error.</p><p><strong>YAML Section:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">raft</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # ... raft configurations ...</span></span></code></pre></div><h3 id="enable-raft" tabindex="-1">Enable Raft <a class="header-anchor" href="#enable-raft" aria-label="Permalink to &quot;Enable Raft&quot;">​</a></h3><p><strong>Description:</strong> If true, enables Raft consensus for leader election and state replication across multiple aggregator nodes.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">raft</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enable</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.raft.enable</code> (boolean, presence enables it) <em>Default:</em> <code>false</code><em>Constant:</em> <code>FlagRaftEnable</code></p><h3 id="raft-node-id" tabindex="-1">Raft Node ID <a class="header-anchor" href="#raft-node-id" aria-label="Permalink to &quot;Raft Node ID&quot;">​</a></h3><p><strong>Description:</strong> Unique identifier for this node within the Raft cluster. Required when Raft is enabled.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">raft</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  node_id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;node1&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.raft.node_id &lt;string&gt;</code><em>Default:</em> <code>&quot;&quot;</code> (required when enabled) <em>Constant:</em> <code>FlagRaftNodeID</code></p><h3 id="raft-address" tabindex="-1">Raft Address <a class="header-anchor" href="#raft-address" aria-label="Permalink to &quot;Raft Address&quot;">​</a></h3><p><strong>Description:</strong> Network address (host:port) for Raft inter-node communication. Required when Raft is enabled.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">raft</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  raft_addr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.0.0.0:7000&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.raft.raft_addr &lt;string&gt;</code><em>Default:</em> <code>&quot;&quot;</code> (required when enabled) <em>Constant:</em> <code>FlagRaftAddr</code></p><h3 id="raft-directory" tabindex="-1">Raft Directory <a class="header-anchor" href="#raft-directory" aria-label="Permalink to &quot;Raft Directory&quot;">​</a></h3><p><strong>Description:</strong> Directory for storing Raft logs and snapshots. Required when Raft is enabled.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">raft</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  raft_dir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/home/user/.evnode/raft&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.raft.raft_dir &lt;string&gt;</code><em>Default:</em> <code>&quot;&lt;home&gt;/raft&quot;</code><em>Constant:</em> <code>FlagRaftDir</code></p><h3 id="raft-bootstrap" tabindex="-1">Raft Bootstrap <a class="header-anchor" href="#raft-bootstrap" aria-label="Permalink to &quot;Raft Bootstrap&quot;">​</a></h3><p><strong>Description:</strong> Legacy compatibility flag. Startup mode is now auto-selected from persisted raft configuration state, so this flag is not used to choose bootstrap vs rejoin.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">raft</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  bootstrap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.raft.bootstrap</code> (boolean, presence enables it) <em>Default:</em> <code>false</code><em>Constant:</em> <code>FlagRaftBootstrap</code></p><h3 id="raft-peers" tabindex="-1">Raft Peers <a class="header-anchor" href="#raft-peers" aria-label="Permalink to &quot;Raft Peers&quot;">​</a></h3><p><strong>Description:</strong> Comma-separated list of peer Raft addresses in <code>nodeID@host:port</code> format.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">raft</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  peers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;node2@192.168.1.2:7000,node3@192.168.1.3:7000&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.raft.peers &lt;string&gt;</code><em>Default:</em> <code>&quot;&quot;</code> (empty) <em>Constant:</em> <code>FlagRaftPeers</code></p><h3 id="raft-startup-mode" tabindex="-1">Raft Startup Mode <a class="header-anchor" href="#raft-startup-mode" aria-label="Permalink to &quot;Raft Startup Mode&quot;">​</a></h3><p>Raft startup mode is selected automatically from local raft configuration state:</p><ul><li>If the node already has persisted raft configuration in <code>raft.raft_dir</code>, it starts in rejoin mode.</li><li>If no raft configuration exists yet, it bootstraps a cluster from configured peers.</li><li><code>raft.bootstrap</code> is retained for compatibility but does not control mode selection.</li></ul><p><code>--evnode.raft.rejoin</code> has been removed.</p><h3 id="raft-snap-count" tabindex="-1">Raft Snap Count <a class="header-anchor" href="#raft-snap-count" aria-label="Permalink to &quot;Raft Snap Count&quot;">​</a></h3><p><strong>Description:</strong> Number of log entries between Raft snapshots. Lower values reduce recovery time but increase snapshot I/O overhead.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">raft</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  snap_count</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10000</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.raft.snap_count &lt;uint64&gt;</code><em>Default:</em> <code>0</code><em>Constant:</em> <code>FlagRaftSnapCount</code></p><h3 id="raft-send-timeout" tabindex="-1">Raft Send Timeout <a class="header-anchor" href="#raft-send-timeout" aria-label="Permalink to &quot;Raft Send Timeout&quot;">​</a></h3><p><strong>Description:</strong> Maximum duration to wait for a message to be sent to a peer before considering it failed.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">raft</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  send_timeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;200ms&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.raft.send_timeout &lt;duration&gt;</code><em>Default:</em> <code>&quot;200ms&quot;</code><em>Constant:</em> <code>FlagRaftSendTimeout</code></p><h3 id="raft-heartbeat-timeout" tabindex="-1">Raft Heartbeat Timeout <a class="header-anchor" href="#raft-heartbeat-timeout" aria-label="Permalink to &quot;Raft Heartbeat Timeout&quot;">​</a></h3><p><strong>Description:</strong> Time between leader heartbeats sent to followers.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">raft</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  heartbeat_timeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;350ms&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.raft.heartbeat_timeout &lt;duration&gt;</code><em>Default:</em> <code>&quot;350ms&quot;</code><em>Constant:</em> <code>FlagRaftHeartbeatTimeout</code></p><h3 id="raft-leader-lease-timeout" tabindex="-1">Raft Leader Lease Timeout <a class="header-anchor" href="#raft-leader-lease-timeout" aria-label="Permalink to &quot;Raft Leader Lease Timeout&quot;">​</a></h3><p><strong>Description:</strong> Duration of the leader lease, which allows a leader to serve reads locally without round-tripping to followers.</p><p><strong>YAML:</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">raft</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  leader_lease_timeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;175ms&quot;</span></span></code></pre></div><p><strong>Command-line Flag:</strong><code>--evnode.raft.leader_lease_timeout &lt;duration&gt;</code><em>Default:</em> <code>&quot;175ms&quot;</code><em>Constant:</em> <code>FlagRaftLeaderLeaseTimeout</code></p><hr><p>This reference should help you configure your Evolve node effectively. Always refer to the specific version of Evolve you are using, as options and defaults may change over time.</p>',397)])])}]]);export{t as __pageData,n as default};
